'use strict';

(function() {
    let incidentes = JSON.parse(localStorage.getItem('k9_incidentes') || '[]');
    let currentIncidente = null;
    const K9_LOGO_SIG = 'data:image/png;base64,';

    window.initIncidentes = function() {
        renderIncidentesList();
    };

    function saveIncidentes() {
        localStorage.setItem('k9_incidentes', JSON.stringify(incidentes));
    }

    function renderIncidentesList() {
        const container = document.getElementById('viewIncidentesList');
        if (!container) return;

        // Metrics
        const total = incidentes.length;
        const criticos = incidentes.filter(i => i.prioridad === 'Crítica').length;

        container.innerHTML = `
            <!-- TACTICAL HERO BANNER -->
            <div class="dash-hero">
                <div class="dash-hero-scanline"></div>
                <div class="dash-hero-inner">
                    <div class="dash-hero-content">
                        <div class="dash-corp-tag"><i class="fas fa-shield-dog"></i> INVESTIGACIÓN DE SUCESOS</div>
                        <h1>Módulo de <span class="accent">Incidentes</span></h1>
                        <p>Documentación técnica y seguimiento de hallazgos, vulnerabilidades y sucesos críticos de seguridad.</p>
                        <div class="dash-hero-actions">
                            <button class="btn-gold btn-lg" onclick="window.createNewIncidente()"><i class="fas fa-plus"></i> Nuevo Informe</button>
                        </div>
                    </div>
                    <div class="dash-hero-stats">
                        <div class="hs-card">
                            <div class="hs-num">${total}</div>
                            <div class="hs-label">Total</div>
                        </div>
                        <div class="hs-card hs-critico">
                            <div class="hs-num">${criticos}</div>
                            <div class="hs-label">Críticos</div>
                        </div>
                    </div>
                </div>
            </div>

            <div class="dash-section">
                <div class="ds-header">
                    <h2><i class="fas fa-file-shield"></i> Informes Registrados</h2>
                    <div class="ds-filters">
                        <div class="search-box">
                            <i class="fas fa-search"></i>
                            <input type="text" id="inc_search" placeholder="Buscar incidente..." oninput="window.filterIncidentes()">
                        </div>
                    </div>
                </div>
                <div id="inc_list_grid" class="eval-list">
                    ${renderIncidentCards(incidentes)}
                </div>
            </div>
        `;
    }

    function renderIncidentCards(items) {
        if (items.length === 0) {
            return `
                <div class="empty-dash">
                    <i class="fas fa-clipboard-check"></i>
                    <h3>No hay incidentes registrados</h3>
                    <p>Haga clic en "Nuevo Informe" para documentar un suceso.</p>
                </div>
            `;
        }

        return items.sort((a,b) => new Date(b.fecha) - new Date(a.fecha)).map(inc => {
            const priorityClass = inc.prioridad === 'Crítica' ? 'badge-critico' : 
                                 inc.prioridad === 'Alta' ? 'badge-deficiente' : 'badge-aceptable';
            return `
                <div class="eval-card">
                    <div class="ec-header">
                        <div class="ec-title-area">
                            <span class="ec-badge ${priorityClass}">${inc.prioridad || 'Media'}</span>
                            <div class="ec-name">${inc.tipo || 'Incidente General'}</div>
                            <div class="ec-site">${inc.lugar}</div>
                        </div>
                        <div class="ec-score-box">
                            <div class="ec-score-val">${inc.fecha.split('-').reverse().join('/')}</div>
                        </div>
                    </div>
                    <div class="ec-body">
                        <div class="ec-meta">
                            <span><i class="fas fa-clock"></i> ${inc.hora || '--:--'}</span>
                            <span><i class="fas fa-building"></i> ${inc.empresa || 'N/A'}</span>
                        </div>
                        <p style="font-size: 11px; color: #64748b; margin-top: 8px; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden;">
                            ${inc.descripcion || 'Sin descripción detallada.'}
                        </p>
                    </div>
                    <div class="ec-footer">
                        <button class="btn-pdf-red" style="padding: 6px 12px; border-radius: 4px; font-size: 11px; cursor: pointer; display: inline-flex; align-items: center; gap: 6px;" onclick="window.exportIncidentePDF('${inc.id}')" title="Exportar PDF"><i class="fas fa-file-pdf"></i> PDF</button>
                        <button class="btn-edit-blue" style="padding: 6px 12px; border-radius: 4px; font-size: 11px; cursor: pointer; display: inline-flex; align-items: center; gap: 6px;" onclick="window.openIncidente('${inc.id}')" title="Editar Informe"><i class="fas fa-edit"></i> Editar</button>
                        <button class="btn-icon del" onclick="window.deleteIncidente('${inc.id}')" title="Eliminar"><i class="fas fa-trash"></i></button>
                    </div>
                </div>
            `;
        }).join('');
    }

    window.filterIncidentes = function() {
        const query = document.getElementById('inc_search').value.toLowerCase();
        const filtered = incidentes.filter(i => 
            i.tipo.toLowerCase().includes(query) || 
            i.lugar.toLowerCase().includes(query) || 
            i.empresa.toLowerCase().includes(query) ||
            i.descripcion.toLowerCase().includes(query)
        );
        document.getElementById('inc_list_grid').innerHTML = renderIncidentCards(filtered);
    };

    window.createNewIncidente = function() {
        currentIncidente = {
            id: 'INC-' + Date.now(),
            fecha: new Date().toISOString().split('T')[0],
            hora: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false }),
            lugar: '',
            empresa: '',
            tipo: 'Hurto',
            prioridad: 'Media',
            descripcion: '',
            involucrados: [],
            acciones: '',
            recomendaciones: '',
            investigador: '',
            fotos: []
        };
        renderIncidenteForm();
    };

    window.openIncidente = function(id) {
        currentIncidente = incidentes.find(i => i.id === id);
        renderIncidenteForm();
    };

    function renderIncidenteForm() {
        const container = document.getElementById('viewIncidentesList');
        const classificationOptions = ['Robo', 'Hurto', 'Intrusión', 'Daño Propiedad', 'Asalto', 'Incendio', 'Emergencia Médica', 'Hallazgo', 'Otro'];
        const priorityOptions = ['Baja', 'Media', 'Alta', 'Crítica'];

        container.innerHTML = `
            <div class="eval-layout" style="height: auto; overflow: visible;">
                <main class="eval-main" style="border-radius: var(--r); box-shadow: var(--shadow2);">
                    <div class="eval-section-header">
                        <div class="esh-num"><i class="fas fa-file-shield"></i></div>
                        <div class="esh-info">
                            <h2>Informe de Investigación</h2>
                            <p>Registre con precisión los hechos, involucrados y evidencias del suceso.</p>
                        </div>
                        <button class="btn-ghost" onclick="window.initIncidentes()"><i class="fas fa-arrow-left"></i> Volver</button>
                    </div>

                    <div class="section-content">
                        <!-- DATOS GENERALES -->
                        <div class="section-card premium-header-card">
                            <div class="form-grid-tactical">
                                <div class="fg-item col-6">
                                    <label><i class="fas fa-calendar"></i> FECHA</label>
                                    <input type="date" id="inc_fecha" value="${currentIncidente.fecha}" class="ai-input-premium">
                                </div>
                                <div class="fg-item col-6">
                                    <label><i class="fas fa-clock"></i> HORA DEL SUCESO</label>
                                    <input type="time" id="inc_hora" value="${currentIncidente.hora}" class="ai-input-premium">
                                </div>
                                <div class="fg-item col-8">
                                    <label><i class="fas fa-location-dot"></i> LUGAR / SITIO EXACTO</label>
                                    <input type="text" id="inc_lugar" value="${currentIncidente.lugar}" class="ai-input-premium" placeholder="Ej: Bodega Norte, Perímetro Este...">
                                </div>
                                <div class="fg-item col-4">
                                    <label><i class="fas fa-tag"></i> TIPO DE SUCESO</label>
                                    <select id="inc_tipo" class="ai-input-premium">
                                        ${classificationOptions.map(opt => `<option value="${opt}" ${currentIncidente.tipo === opt ? 'selected' : ''}>${opt}</option>`).join('')}
                                    </select>
                                </div>
                                <div class="fg-item col-8">
                                    <label><i class="fas fa-building"></i> EMPRESA CLIENTE</label>
                                    <input type="text" id="inc_empresa" value="${currentIncidente.empresa}" class="ai-input-premium" placeholder="Nombre de la empresa">
                                </div>
                                <div class="fg-item col-4">
                                    <label><i class="fas fa-triangle-exclamation"></i> PRIORIDAD</label>
                                    <select id="inc_prioridad" class="ai-input-premium">
                                        ${priorityOptions.map(opt => `<option value="${opt}" ${currentIncidente.prioridad === opt ? 'selected' : ''}>${opt}</option>`).join('')}
                                    </select>
                                </div>
                            </div>
                        </div>

                        <!-- DESCRIPCIÓN DE HECHOS -->
                        <div class="section-card">
                            <div class="sc-title"><i class="fas fa-align-left"></i> Narrativa de los Hechos (¿Qué sucedió?)</div>
                            <div class="field-mic-wrapper">
                                <textarea id="inc_desc" class="ai-input" style="width:100%; min-height:150px" placeholder="Describa detalladamente el evento de forma cronológica...">${currentIncidente.descripcion}</textarea>
                                <button type="button" class="btn-field-mic-ui" onclick="activateVoiceField('inc_desc')"><i class="fas fa-microphone"></i></button>
                            </div>
                        </div>

                        <!-- PERSONAS INVOLUCRADAS -->
                        <div class="section-card">
                            <div class="sc-title"><i class="fas fa-users-viewfinder"></i> Personas Involucradas</div>
                            <div id="inc_involucrados_list" class="findings-list">
                                ${currentIncidente.involucrados.map((p, i) => `
                                    <div class="finding-item" style="display: grid; grid-template-columns: 1fr 1fr 40px; gap: 10px; margin-bottom: 10px;">
                                        <input type="text" class="ai-input" value="${p.nombre}" placeholder="Nombre Completo" oninput="currentIncidente.involucrados[${i}].nombre=this.value">
                                        <input type="text" class="ai-input" value="${p.rol}" placeholder="Rol (Víctima, Testigo, Sospechoso)" oninput="currentIncidente.involucrados[${i}].rol=this.value">
                                        <button class="btn-icon del" onclick="window.removeInvolucrado(${i})"><i class="fas fa-times"></i></button>
                                    </div>
                                `).join('')}
                            </div>
                            <button class="btn-add-finding" onclick="window.addInvolucrado()"><i class="fas fa-user-plus"></i> Agregar Involucrado</button>
                        </div>

                        <!-- ACCIONES Y RECOMENDACIONES -->
                        <div class="section-card">
                            <div class="form-grid-tactical">
                                <div class="fg-item col-6">
                                    <label><i class="fas fa-bolt"></i> ACCIONES INMEDIATAS TOMADAS</label>
                                    <textarea id="inc_acciones" class="ai-input" style="height:100px">${currentIncidente.acciones}</textarea>
                                </div>
                                <div class="fg-item col-6">
                                    <label><i class="fas fa-lightbulb"></i> RECOMENDACIONES PREVENTIVAS</label>
                                    <textarea id="inc_recom" class="ai-input" style="height:100px">${currentIncidente.recomendaciones}</textarea>
                                </div>
                            </div>
                        </div>

                        <!-- EVIDENCIA FOTOGRÁFICA -->
                        <div class="section-card">
                            <div class="sc-title"><i class="fas fa-camera"></i> Evidencia Fotográfica</div>
                            <div id="inc_evidence_grid" style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; margin-bottom: 15px;">
                                ${currentIncidente.fotos.map((img, i) => `
                                    <div style="position: relative; aspect-ratio: 16/9; border-radius: 4px; overflow: hidden; border: 1px solid var(--border);">
                                        <img src="${img}" style="width:100%; height:100%; object-fit:cover;">
                                        <button class="btn-icon del" style="position:absolute; top:4px; right:4px; transform:scale(0.8)" onclick="window.removeIncEvidence(${i})"><i class="fas fa-trash"></i></button>
                                    </div>
                                `).join('')}
                                <button class="btn-add-finding" style="aspect-ratio: 16/9; height: auto;" onclick="document.getElementById('inc_img_input').click()">
                                    <i class="fas fa-plus" style="font-size: 20px;"></i><br><span style="font-size: 10px;">Añadir Foto</span>
                                </button>
                            </div>
                            <input type="file" id="inc_img_input" style="display:none" accept="image/*" onchange="window.uploadIncEvidence(this)">
                        </div>

                        <!-- FIRMA DIGITAL Y RESPONSABLE -->
                        <div class="section-card">
                            <div class="sc-title"><i class="fas fa-pen-nib"></i> Firma Digital del Investigador</div>
                            <div style="display: flex; gap: 20px; align-items: center; background: #f8fafc; padding: 20px; border-radius: 8px; border: 1px solid var(--border);">
                                <div id="inc_sig_preview" style="width: 180px; height: 80px; border: 2px dashed var(--border); border-radius: 6px; display: flex; align-items: center; justify-content: center; background: #fff; overflow: hidden;">
                                    ${localStorage.getItem('k9_evaluator_signature') ? `<img src="${localStorage.getItem('k9_evaluator_signature')}" style="max-width: 100%; max-height: 100%; object-fit: contain;">` : '<i class="fas fa-image" style="font-size: 24px; color: #cbd5e1;"></i>'}
                                </div>
                                <div style="flex: 1;">
                                    <div class="fg-item" style="margin-bottom: 12px;">
                                        <label style="font-size: 10px;">NOMBRE DEL INVESTIGADOR</label>
                                        <div class="field-mic-wrapper">
                                            <input type="text" id="inc_investigador" value="${currentIncidente.investigador}" class="ai-input" placeholder="Nombre completo">
                                            <button type="button" class="btn-field-mic-ui" onclick="activateVoiceField('inc_investigador')"><i class="fas fa-microphone"></i></button>
                                        </div>
                                    </div>
                                    <div style="display: flex; gap: 10px;">
                                        <button class="btn-primary" style="padding: 8px 16px; font-size: 11px;" onclick="document.getElementById('inc_sig_input').click()"><i class="fas fa-upload"></i> Cargar Nueva Firma</button>
                                        <button class="btn-ghost" style="color: var(--del); font-size: 11px;" onclick="window.removeIncSignature()"><i class="fas fa-trash"></i> Quitar</button>
                                    </div>
                                    <input type="file" id="inc_sig_input" style="display: none;" accept="image/*" onchange="window.uploadIncSignature(this)">
                                </div>
                            </div>
                        </div>
                    </div>

                    <div class="eval-nav-bar">
                        <button class="btn-ghost" onclick="window.initIncidentes()">Cancelar</button>
                        <button class="btn-primary" onclick="window.saveCurrentIncidente()"><i class="fas fa-save"></i> Finalizar Informe</button>
                    </div>
                </main>
            </div>
        `;
    }

    function syncIncFromDOM() {
        if (!currentIncidente) return;
        currentIncidente.fecha = document.getElementById('inc_fecha').value;
        currentIncidente.hora = document.getElementById('inc_hora').value;
        currentIncidente.lugar = document.getElementById('inc_lugar').value;
        currentIncidente.tipo = document.getElementById('inc_tipo').value;
        currentIncidente.empresa = document.getElementById('inc_empresa').value;
        currentIncidente.prioridad = document.getElementById('inc_prioridad').value;
        currentIncidente.descripcion = document.getElementById('inc_desc').value;
        currentIncidente.acciones = document.getElementById('inc_acciones').value;
        currentIncidente.recomendaciones = document.getElementById('inc_recom').value;
        currentIncidente.investigador = document.getElementById('inc_investigador').value;
    }

    window.addInvolucrado = function() {
        syncIncFromDOM();
        currentIncidente.involucrados.push({ nombre: '', rol: '' });
        renderIncidenteForm();
    };

    window.removeInvolucrado = function(idx) {
        syncIncFromDOM();
        currentIncidente.involucrados.splice(idx, 1);
        renderIncidenteForm();
    };

    window.uploadIncEvidence = function(input) {
        if (input.files && input.files[0]) {
            const reader = new FileReader();
            reader.onload = function(e) {
                currentIncidente.fotos.push(e.target.result);
                renderIncidenteForm();
            };
            reader.readAsDataURL(input.files[0]);
        }
    };

    window.removeIncEvidence = function(idx) {
        currentIncidente.fotos.splice(idx, 1);
        renderIncidenteForm();
    };

    window.saveCurrentIncidente = function() {
        syncIncFromDOM();
        if (!currentIncidente.lugar || !currentIncidente.descripcion) {
            alert('Por favor complete el lugar y la descripción del suceso.');
            return;
        }
        const idx = incidentes.findIndex(i => i.id === currentIncidente.id);
        if (idx >= 0) incidentes[idx] = currentIncidente;
        else incidentes.push(currentIncidente);
        
        saveIncidentes();
        window.initIncidentes();
        if (window.showToast) window.showToast('Informe guardado correctamente.', 'success');
    };

    window.deleteIncidente = function(id) {
        if (confirm('¿Desea eliminar este informe? Esta acción es irreversible.')) {
            incidentes = incidentes.filter(i => i.id !== id);
            saveIncidentes();
            renderIncidentesList();
        }
    };

    window.exportIncidentePDF = function(id) {
        const inc = incidentes.find(i => i.id === id);
        if (!inc) return;

        const signatureImg = localStorage.getItem('k9_evaluator_signature');

        const html = `
        <!DOCTYPE html>
        <html lang="es">
        <head>
            <meta charset="UTF-8">
            <title>Informe de Incidente K-9 - ${inc.id}</title>
            <style>
                @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;800&display=swap');
                :root { --navy: #0f172a; --gold: #c8951a; --border: #e2e8f0; --bg: #f8fafc; --critico: #ef4444; }
                body { font-family: 'Inter', sans-serif; padding: 40px; color: #1e293b; line-height: 1.4; font-size: 11px; margin: 0; }
                
                .header-table { width: 100%; border: 1px solid var(--navy); border-collapse: collapse; margin-bottom: 20px; }
                .header-table td { border: 1px solid var(--navy); padding: 8px; vertical-align: middle; }
                .logo-text { font-weight: 800; color: var(--navy); font-size: 18px; letter-spacing: -1px; text-align: center; }
                .title-box { text-align: center; font-weight: 800; font-size: 13px; background: #f1f5f9; color: var(--navy); }
                .meta-box { width: 150px; font-size: 8px; color: #64748b; line-height: 1.6; text-align: right; }

                .priority-banner { background: ${inc.prioridad === 'Crítica' ? '#fee2e2' : '#f1f5f9'}; border: 1px solid ${inc.prioridad === 'Crítica' ? '#ef4444' : '#e2e8f0'}; padding: 10px; margin-bottom: 15px; border-radius: 4px; display: flex; justify-content: space-between; align-items: center; }
                .priority-banner .label { font-weight: 800; color: ${inc.prioridad === 'Crítica' ? '#b91c1c' : '#475569'}; text-transform: uppercase; }

                .info-table { width: 100%; border-collapse: collapse; margin-bottom: 15px; }
                .info-table td { padding: 6px 10px; border: 1px solid var(--border); }
                .label { font-weight: 600; background: var(--bg); width: 120px; color: #475569; }
                .val { font-weight: 600; color: var(--navy); }

                .section-bar { background: var(--navy); color: white; padding: 5px 12px; font-weight: 600; margin-top: 15px; border-radius: 2px; text-transform: uppercase; font-size: 10px; }
                
                .text-area { border: 1px solid var(--border); padding: 12px; min-height: 80px; margin-top: 10px; background: #fff; white-space: pre-wrap; font-size: 11px; }

                .data-table { width: 100%; border-collapse: collapse; margin-top: 10px; }
                .data-table th { background: var(--bg); border: 1px solid var(--border); padding: 8px; text-align: left; font-size: 9px; text-transform: uppercase; }
                .data-table td { border: 1px solid var(--border); padding: 8px; }

                .evidence-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-top: 10px; }
                .evidence-img { width: 100%; aspect-ratio: 16/9; object-fit: cover; border: 1px solid var(--border); }

                .footer-sign { margin-top: 40px; display: flex; justify-content: center; }
                .sign-wrapper { text-align: center; width: 300px; display: flex; flex-direction: column; align-items: center; }
                .sig-img { max-width: 180px; max-height: 60px; object-fit: contain; margin-bottom: 5px; }
                .sig-line { width: 100%; border-top: 1px solid var(--navy); padding-top: 8px; }

                .watermark { position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%) rotate(-45deg); font-size: 50px; color: rgba(15, 23, 42, 0.03); font-weight: 900; z-index: -1; white-space: nowrap; pointer-events: none; }
            </style>
        </head>
        <body>
            <div class="watermark">K-9 INVESTIGATION UNIT</div>
            
            <table class="header-table">
                <tr>
                    <td style="width: 100px;"><img src="${K9_LOGO_SIG}" style="height: 50px; width: auto; display: block; margin: 0 auto;"></td>
                    <td class="title-box">INFORME DE INCIDENTE Y HALLAZGOS<br>INVESTIGACIÓN DE SEGURIDAD PATRIMONIAL</td>
                    <td class="meta-box">
                        ID: ${inc.id}<br>
                        FECHA REF: ${inc.fecha}<br>
                        CONFIDENCIAL
                    </td>
                </tr>
            </table>

            <div class="priority-banner">
                <span class="label">Prioridad: ${inc.prioridad}</span>
                <span class="label">Tipo: ${inc.tipo}</span>
            </div>

            <table class="info-table">
                <tr>
                    <td class="label">Lugar/Sitio:</td>
                    <td class="val">${inc.lugar}</td>
                    <td class="label">Empresa:</td>
                    <td class="val">${inc.empresa || 'N/A'}</td>
                </tr>
                <tr>
                    <td class="label">Fecha Suceso:</td>
                    <td class="val">${inc.fecha}</td>
                    <td class="label">Hora Suceso:</td>
                    <td class="val">${inc.hora}</td>
                </tr>
            </table>

            <div class="section-bar">1. NARRATIVA DE LOS HECHOS</div>
            <div class="text-area">${inc.descripcion}</div>

            <div class="section-bar">2. PERSONAS INVOLUCRADAS</div>
            <table class="data-table">
                <thead>
                    <tr><th>Nombre Completo</th><th>Rol / Relación</th></tr>
                </thead>
                <tbody>
                    ${inc.involucrados.map(p => `<tr><td>${p.nombre}</td><td>${p.rol}</td></tr>`).join('') || '<tr><td colspan="2">No se reportaron involucrados específicos.</td></tr>'}
                </tbody>
            </table>

            <div class="section-bar">3. ACCIONES Y RECOMENDACIONES</div>
            <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 15px;">
                <div>
                    <h4 style="margin: 10px 0 5px 0;">Acciones Tomadas:</h4>
                    <div class="text-area" style="min-height:60px">${inc.acciones || '-'}</div>
                </div>
                <div>
                    <h4 style="margin: 10px 0 5px 0;">Medidas Preventivas:</h4>
                    <div class="text-area" style="min-height:60px">${inc.recomendaciones || '-'}</div>
                </div>
            </div>

            ${inc.fotos.length > 0 ? `
                <div class="section-bar">4. EVIDENCIA FOTOGRÁFICA</div>
                <div class="evidence-grid">
                    ${inc.fotos.map(img => `<img src="${img}" class="evidence-img">`).join('')}
                </div>
            ` : ''}

            <div class="footer-sign">
                <div class="sign-wrapper">
                    ${signatureImg ? `<img src="${signatureImg}" class="sig-img">` : '<div style="height:50px"></div>'}
                    <div class="sig-line">
                        <strong style="text-transform: uppercase;">${inc.investigador || 'Agente de Seguridad'}</strong><br>
                        <span style="font-size: 8px; color: var(--gold);">INVESTIGADOR CORPORACIÓN K-9</span>
                    </div>
                </div>
            </div>

            <script>window.onload = function() { window.print(); setTimeout(() => { window.close(); }, 1000); }</script>
        </body>
        </html>
        `;

        const win = window.open('', '_blank');
        win.document.write(html);
        win.document.close();
    };

    window.uploadIncSignature = function(input) {
        if (input.files && input.files[0]) {
            const reader = new FileReader();
            reader.onload = function(e) {
                localStorage.setItem('k9_evaluator_signature', e.target.result);
                // Refresh preview
                syncIncFromDOM();
                renderIncidenteForm();
            };
            reader.readAsDataURL(input.files[0]);
        }
    };

    window.removeIncSignature = function() {
        if (confirm('¿Desea eliminar la firma digital guardada?')) {
            localStorage.removeItem('k9_evaluator_signature');
            syncIncFromDOM();
            renderIncidenteForm();
        }
    };

    window.getCurrentIncidente = () => currentIncidente;

})();
